import{_ as t,o,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse(`{"title":"21A. Employee Right To Disconnect","description":"","frontmatter":{"title":"21A. Employee Right To Disconnect","eba":"Children's Services Award 2010","topics":["hours","rosters","right-to-disconnect"]},"headers":[],"relativePath":"ebas/childrens-services/hours-of-work/21A-employee-right-to-disconnect.md","filePath":"ebas/childrens-services/hours-of-work/21A-employee-right-to-disconnect.md"}`),s={name:"ebas/childrens-services/hours-of-work/21A-employee-right-to-disconnect.md"};function a(i,e,c,l,p,h){return o(),r("div",null,[...e[0]||(e[0]=[n(`<h1 id="_21a-employee-right-to-disconnect" tabindex="-1">21A. Employee Right To Disconnect <a class="header-anchor" href="#_21a-employee-right-to-disconnect" aria-label="Permalink to &quot;21A. Employee Right To Disconnect&quot;">​</a></h1><p><strong>21A.1</strong> Clause 21A provides for the exercise of an employee&#39;s right to disconnect under section 333M of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p><p>NOTE:</p><blockquote><p>(a) Section 333M provides that, unless it is unreasonable to do so, an employee may refuse to monitor, read or respond to contact, or attempted contact, from:</p><p>(1) their employer outside of the employee&#39;s working hours,</p><p>(2) a third party if the contact or attempted contact relates to, their work and is outside of the employee\\s working hours.</p><p>(b) Section 333M(3) lists matters that must be taken into account in determining whether an employee&#39;s refusal is unreasonable.</p><p>(c) Section 333M(5) provides that an employee&#39;s refusal will be unreasonable if the contact or attempted contact is required under a law of the Commonwealth, a State or a Territory.</p><p>(d) Section 333N provides for the resolution of disputes about whether an employee&#39;s refusal is unreasonable and about the operation of section 333M.</p><p>(e) The general protections in Part 3--1 of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a> prohibit an employer taking adverse action against an employee because of the employee&#39;s right to disconnect under section 333M of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p></blockquote><p><strong>21A.2</strong> Clause 21A applies from the following dates:</p><p>i. 26 August 2024---for employers that are not small business employers on this date and their employees.</p><p>j. 26 August 2025---for employers that are small business employers on 26 August 2024 and their employees.</p><pre><code>**21A.3** An employer must not directly or indirectly prevent an
employee from exercising their right to disconnect under the
[Act](http://www.legislation.gov.au/Series/C2009A00028).

**21A.4** Clause 21A.3 does not prevent an employer from contacting,
or attempting to contact, an employee outside of the employee&#39;s
working hours in circumstances including to notify them of an
emergency roster change under [clause 10](/ebas/childrens-services/employment/10-types-of-employment).4(d) or 21.7(b).
</code></pre><p>Plain language terms: disconnect, after hours contact.</p>`,9)])])}const u=t(s,[["render",a]]);export{d as __pageData,u as default};
